const prev = global.get("equipment_runtime") || {};
const prevPushTopics = global.get("allowed_push_topics") || {};

let cfg = msg.payload;
if (typeof cfg === "string") {
    try {
        cfg = JSON.parse(cfg);
    } catch (err) {
        node.warn(`equipment config parse failed: ${err.message}`);
        msg.payload = {
            total: Object.keys(prev).length,
            added: [],
            updated: [],
            removed: [],
            preserved_runtime: true,
            error: "config_parse_failed"
        };
        return msg;
    }
}

if (!Array.isArray(cfg)) {
    node.warn("equipment config payload is not an array; keeping previous runtime");
    msg.payload = {
        total: Object.keys(prev).length,
        added: [],
        updated: [],
        removed: [],
        preserved_runtime: true,
        error: "config_not_array"
    };
    return msg;
}

const next = {};
const allowedPushTopics = {};
const added = [];
const updated = [];
const removed = [];

function isValid(item) {
    if (!item || !item.equipment_id || !item.type || !item.protocol) return false;
    if (!item.endpoint || typeof item.endpoint !== "object") return false;
    if (item.type === "poll") {
        if (!(item.protocol === "modbus" || item.protocol === "opcua")) return false;
        if (!item.endpoint.host || !item.endpoint.port) return false;
        if (!item.poll_interval_sec || item.poll_interval_sec <= 0) return false;
    }
    if (item.type === "push") {
        if (item.protocol !== "mqtt") return false;
        if (!item.endpoint.host || !item.endpoint.port || !item.endpoint.topic) return false;
    }
    return true;
}

for (const item of cfg) {
    if (!isValid(item)) continue;
    const eid = item.equipment_id;
    const signature = JSON.stringify({
        equipment_id: item.equipment_id,
        type: item.type,
        protocol: item.protocol,
        endpoint: item.endpoint,
        poll_interval_sec: item.poll_interval_sec,
        mapping: item.mapping || {},
        timeout_sec: item.timeout_sec || 60
    });

    const prevEntry = prev[eid] || {};
    next[eid] = {
        config: item,
        signature,
        last_poll_ts: prevEntry.last_poll_ts || 0,
        alarm_until_ts: prevEntry.alarm_until_ts || 0,
        stable_until_ts: prevEntry.stable_until_ts || 0,
        current_raw: prevEntry.current_raw,
        last_emitted_status: prevEntry.last_emitted_status || null
    };

    if (!prev[eid]) added.push(eid);
    else if (prev[eid].signature !== signature) updated.push(eid);

    if (item.type === "push" && item.endpoint.topic) {
        allowedPushTopics[item.endpoint.topic] = {
            equipment_id: eid,
            mapping: item.mapping || {}
        };
    }
}

if (cfg.length > 0 && Object.keys(next).length === 0) {
    node.warn("equipment config contains no valid entries; keeping previous runtime");
    msg.payload = {
        total: Object.keys(prev).length,
        added: [],
        updated: [],
        removed: [],
        preserved_runtime: true,
        error: "config_has_no_valid_entries"
    };
    return msg;
}

for (const oldId of Object.keys(prev)) {
    if (!next[oldId]) removed.push(oldId);
}

global.set("equipment_runtime", next);
global.set("allowed_push_topics", Object.keys(allowedPushTopics).length ? allowedPushTopics : prevPushTopics);

msg.payload = {
    total: Object.keys(next).length,
    added,
    updated,
    removed,
    preserved_runtime: false
};
return msg;

const runtime = global.get("equipment_runtime") || {};
const now = Date.now();
const events = [];
const pollRawValues = [0, 1, 1, 1, 1, 2];

function selectDurationSec(raw) {
    if (raw === 2) return 30 + Math.floor(Math.random() * 91);
    if (raw === 0) return 20 + Math.floor(Math.random() * 41);
    return 40 + Math.floor(Math.random() * 141);
}

function nextRaw(previousRaw) {
    let raw = pollRawValues[Math.floor(Math.random() * pollRawValues.length)];
    if (previousRaw !== undefined && pollRawValues.length > 1) {
        while (raw === previousRaw) {
            raw = pollRawValues[Math.floor(Math.random() * pollRawValues.length)];
        }
    }
    return raw;
}

function mapStatus(raw, mapping) {
    const statusMap = (mapping && mapping.status_map) || { "0": "STOP", "1": "RUN", "2": "ALARM" };
    return statusMap[String(raw)] || (raw === 2 ? "ALARM" : raw === 0 ? "STOP" : "RUN");
}

for (const [equipmentId, entry] of Object.entries(runtime)) {
    const cfg = entry.config || {};
    if (cfg.type !== "poll") continue;

    const intervalSec = Math.max(1, Number(cfg.poll_interval_sec) || 2);
    if (entry.last_poll_ts && (now - entry.last_poll_ts) < intervalSec * 1000) continue;

    if (typeof entry.current_raw === "undefined" || now >= (entry.stable_until_ts || 0)) {
        entry.current_raw = nextRaw(entry.current_raw);
        entry.stable_until_ts = now + selectDurationSec(entry.current_raw) * 1000;
    }

    const status = mapStatus(entry.current_raw, cfg.mapping || {});
    entry.last_poll_ts = now;
    entry.last_emitted_status = status;
    runtime[equipmentId] = entry;

    events.push({
        equipment_id: equipmentId,
        status,
        ts: new Date(now).toISOString(),
        payload: {
            source: cfg.protocol || "poll",
            endpoint: cfg.endpoint || {},
            raw: entry.current_raw
        }
    });
}

global.set("equipment_runtime", runtime);
msg.payload = events;
return msg;

const allowedPushTopics = global.get("allowed_push_topics") || {};
const topic = msg.topic || "";
const meta = allowedPushTopics[topic] || null;
let equipmentId = meta && meta.equipment_id;
const mapping = (meta && meta.mapping) || {};

if (!equipmentId) {
    const parts = topic.split("/");
    if (parts.length >= 3 && parts[0] === "equip" && parts[parts.length - 1] === "status") {
        equipmentId = parts[1];
    }
}

if (!equipmentId) {
    return null;
}

let rawPayload = msg.payload;
if (Buffer.isBuffer(rawPayload)) {
    rawPayload = rawPayload.toString("utf8");
}
if (typeof rawPayload === "string") {
    try {
        rawPayload = JSON.parse(rawPayload);
    } catch (err) {
        // keep raw string payload
    }
}

let rawValue = rawPayload;
if (rawPayload && typeof rawPayload === "object" && rawPayload.raw !== undefined) {
    rawValue = rawPayload.raw;
}

function mapStatus(value, mappingCfg) {
    const statusMap = (mappingCfg && mappingCfg.status_map) || { "0": "STOP", "1": "RUN", "2": "ALARM" };
    if (typeof value === "string") {
        const upper = value.trim().toUpperCase();
        if (["RUN", "STOP", "ALARM", "IDLE", "OFFLINE"].includes(upper)) {
            return upper;
        }
        if (statusMap[upper]) {
            return statusMap[upper];
        }
    }

    const numeric = Number(value);
    if (Number.isFinite(numeric)) {
        return statusMap[String(numeric)] || (numeric === 2 ? "ALARM" : numeric === 0 ? "STOP" : "RUN");
    }

    return "RUN";
}

msg.payload = {
    equipment_id: equipmentId,
    status: mapStatus(rawValue, mapping),
    ts: new Date().toISOString(),
    payload: {
        source: "mqtt",
        topic,
        raw: rawPayload
    }
};
return msg;
